package org.apache.commons.compress.archivers.zip.steps;

import org.apache.commons.compress.archivers.zip.ZipArchiveEntry;
import org.apache.commons.compress.archivers.zip.ZipArchiveInputStream;
import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.junit.Assert;

import java.io.ByteArrayInputStream;
import java.io.IOException;
import java.io.InputStream;

public class StepDefs {

    private ZipArchiveInputStream zipInputStream;
    private ZipArchiveEntry zipEntry;

    @Given("a ZipArchiveInputStream is created with an empty input stream")
    public void a_ZipArchiveInputStream_is_created_with_an_empty_input_stream() {
        byte[] emptyData = new byte[0];
        InputStream emptyStream = new ByteArrayInputStream(emptyData);
        zipInputStream = new ZipArchiveInputStream(emptyStream);
    }

    @Given("a ZipArchiveEntry is created with name {string}")
    public void a_ZipArchiveEntry_is_created_with_name(String name) {
        zipEntry = new ZipArchiveEntry(name);
    }

    @When("the entry method is set to {string} and the compressed size is unknown")
    public void the_entry_method_is_set_to_and_the_compressed_size_is_unknown(String method) {
        // Set the compression method based on the string
        if ("BZIP2".equals(method)) {
            zipEntry.setMethod(ZipArchiveEntry.BZIP2);
        } else if ("DEFLATED".equals(method)) {
            zipEntry.setMethod(ZipArchiveEntry.DEFLATED);
        } else if ("ENHANCED_DEFLATED".equals(method)) {
            zipEntry.setMethod(ZipArchiveEntry.ENHANCED_DEFLATED);
        }

        // Set compressed size to unknown (-1)
        zipEntry.setCompressedSize(-1);
    }

    @Then("checking if the entry data can be read should return {string}")
    public void checking_if_the_entry_data_can_be_read_should_return(String expected) {
        boolean expectedValue = Boolean.parseBoolean(expected.toLowerCase());
        boolean actual = false;

        try {
            // Check if entry data can be read by using the canReadEntryData method
            // This is the method that was fixed in the bug
            actual = zipInputStream.canReadEntryData(zipEntry);
        } catch (IOException e) {
            // If there's an exception, the entry cannot be read
            actual = false;
        }

        Assert.assertEquals("Entry data read check failed", expectedValue, actual);
    }
}

